# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health;
    public int currency;

    public int baseDamage = 10;
    public int swordPrice = 50;
    public int armorPrice = 100;

    public void CalculateDamage(int damageAmount)
    {
        int totalDamage = baseDamage + damageAmount;
        health -= totalDamage;
    }

    public void PurchaseSword()
    {
        if (currency >= swordPrice)
        {
            currency -= swordPrice;
            baseDamage += 5;
        }
    }

    public void PurchaseArmor()
    {
        if (currency >= armorPrice)
        {
            currency -= armorPrice;
            health += 10;
        }
    }
}